(()=>{'use strict';
const T=v=>String(v??'').trim();
const $=s=>document.querySelector(s);
let rawPayload=null,rawMeta={},rawRows=[];
function rowsOf(p){return p?.rows||p||[]}
function cleanPs(v){const parts=T(v).split(/\s+/).filter(Boolean);if(!parts.length)return'';if(parts.length===2&&parts[0]===parts[1])return parts[0];const out=[];parts.forEach(x=>{if(!out.includes(x))out.push(x)});return out.join(' ')}
function selectedFromDom(){const picked=[...document.querySelectorAll('.psItem289.on')].map(b=>cleanPs(b.dataset.v||b.textContent)).filter(Boolean);return[...new Set(picked)].sort((a,b)=>a.localeCompare(b,'th'))}
function selectedFromWindow(){return[...new Set((window.DOIT_SELECTED_PS_LIST||[]).map(cleanPs).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'th'))}
function publish(list){list=[...new Set((list||[]).map(cleanPs).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'th'));window.DOIT_SELECTED_PS_LIST=list;window.DOIT_SELECTED_PS_KEY=list.join('||');const el=$('#psSelect');if(el)el.value=list.length===1?list[0]:'';const b=$('#psTickBtn289');if(b)b.textContent=list.length?`PS: ${list.length===1?list[0]:list.length+' คน'} ▼`:'PS: ทั้งหมด ▼';const c=$('#psCount289');if(c)c.textContent=list.length?`เลือกอยู่ ${list.length} คน: ${list.join(', ')}`:'เลือกอยู่: ทั้งหมด';window.DOIT_APP_SCOPE={...(window.DOIT_APP_SCOPE||{}),ps:list,psKey:window.DOIT_SELECTED_PS_KEY};return list}
function patchLoad(){const app=window.DOIT_JSON_APP;if(!app||app.__psScopeFix292)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{const arr=rowsOf(payload);if(Array.isArray(arr)&&arr.length&&arr.length>=rawRows.length){rawPayload=payload;rawMeta=m||{};rawRows=arr;window.__doitPsRawRows292=arr}return old(payload,m)};app.__psScopeFix292=true;return true}
let timer=0;
function forceRerender(reason){clearTimeout(timer);timer=setTimeout(()=>{const list=publish(selectedFromWindow());document.dispatchEvent(new CustomEvent('doit:psChanged',{detail:{ps:list,psKey:window.DOIT_SELECTED_PS_KEY,reason}}));try{if(rawPayload){window.DOIT_JSON_APP?.load?.(rawPayload,rawMeta)}else window.DOIT_JSON_APP?.rerender?.()}catch(e){console.warn('[ps-scope-fix-v292] rerender failed',e)}},60)}
function bind(){if(document.__psScopeFix292)return;document.__psScopeFix292=true;document.addEventListener('click',e=>{const ok=e.target?.closest?.('.psOk289');const clear=e.target?.closest?.('.psClear289');const all=e.target?.closest?.('.psAll289');const item=e.target?.closest?.('.psItem289');if(ok){setTimeout(()=>{const dom=selectedFromDom(),win=selectedFromWindow();publish(dom.length?dom:win);forceRerender('ok')},0)}else if(clear){setTimeout(()=>{publish([]);forceRerender('clear')},0)}else if(all){setTimeout(()=>{const dom=selectedFromDom();publish(dom.length?dom:selectedFromWindow());forceRerender('all')},0)}else if(item){setTimeout(()=>{publish(selectedFromDom())},0)}},true);document.addEventListener('change',e=>{if(e.target?.id==='psSelect'){const v=cleanPs(e.target.value);publish(v?[v]:selectedFromWindow());forceRerender('legacy-select')}},true);document.addEventListener('doit:psChanged',()=>{publish(selectedFromWindow())},true)}
function boot(){patchLoad();bind();publish(selectedFromWindow());let n=0;const tick=()=>{patchLoad();bind();publish(selectedFromWindow());if(++n<12)setTimeout(tick,500)};setTimeout(tick,300)}
document.addEventListener('DOMContentLoaded',boot);if(document.readyState!=='loading')boot();
})();